code = """import json
import os

# Load articles
articles_file = '/tmp/data_output_var_functions.query_db:60.json'
articles = []
if os.path.exists(articles_file):
    with open(articles_file, 'r') as f:
        articles = json.load(f)

# Define keywords for categories as per hints
sports_keywords = ['football', 'soccer', 'basketball', 'baseball', 'tennis', 'golf', 'cricket', 'hockey', 'rugby', 'athlete', 'olympics', 'olympic', 'championship', 'tournament', 'coach', 'player', 'team', 'game', 'medal', 'sports', 'nba', 'nfl', 'mlb', 'nhl']
business_keywords = ['stock', 'market', 'economy', 'business', 'company', 'ipo', 'trade', 'oil', 'google', 'wall st', 'wall street', 'nasdaq']
world_keywords = ['iraq', 'iran', 'war', 'peace', 'conflict', 'refugee', 'united nations', 'diplomatic', 'israel', 'palestine']
tech_keywords = ['technology', 'software', 'hardware', 'computer', 'chip', 'digital', 'internet', 'microsoft', 'research', 'science', 'scientist']

def categorize_article(article):
    title = article.get('title', '').lower()
    desc = article.get('description', '').lower()
    text = title + ' ' + desc
    
    # Count keywords
    sports_count = sum(1 for kw in sports_keywords if kw in text)
    business_count = sum(1 for kw in business_keywords if kw in text)
    world_count = sum(1 for kw in world_keywords if kw in text)
    tech_count = sum(1 for kw in tech_keywords if kw in text)
    
    # Find max
    counts = {'Sports': sports_count, 'Business': business_count, 'World': world_count, 'Science/Technology': tech_count}
    max_category = max(counts, key=counts.get)
    return max_category if counts[max_category] > 0 else 'Uncategorized'

# Find sports articles
sports_articles = []
longest_sports = None
max_len = 0

for article in articles:
    category = categorize_article(article)
    desc_len = len(article.get('description', ''))
    
    if category == 'Sports':
        sports_articles.append({'title': article.get('title'), 'length': desc_len})
        if desc_len > max_len:
            max_len = desc_len
            longest_sports = article

# Sort and get answer
if sports_articles:
    sports_articles.sort(key=lambda x: x['length'], reverse=True)
    answer_title = longest_sports.get('title')
    answer_length = max_len
else:
    answer_title = None
    answer_length = 0

result = {'title': answer_title, 'length': answer_length, 'count': len(sports_articles)}

print('__RESULT__:')
print(json.dumps(result))"""

